/// <reference path="./types/express.d.ts" />
import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { env } from "./env.js";
import { logger } from "./lib/logger.js";
import jwt from "jsonwebtoken";
import crypto from "crypto";

import { redis } from "./lib/redis.js";
import { getIsProd } from "./lib/is-prod.js";

if (getIsProd() && !redis) {
    logger.warn({ context: "auth" }, "Redis is not configured in production. Token blacklist is disabled.");
}

/**
 * Revokes a JWT token by adding it to the blacklist
 */
export async function revokeToken(token: string) {
    if (!redis) return; // Skip if no Redis

    try {
        const decoded = jwt.decode(token) as { exp?: number } | null;
        if (decoded?.exp) {
            const ttl = Math.max(0, decoded.exp - Math.floor(Date.now() / 1000));
            if (ttl > 0) {
                // Store in Redis with TTL so it expires automatically
                await redis.set(`blacklist:${token}`, "1", "EX", ttl);
            }
        }
    } catch (err) {
        logger.error({ context: "auth", error: err }, "Failed to revoke token");
    }
}

// --- Refresh Token Helpers (stateless JWT — no Redis required) ---
//
// Previously these used a random hex token whose hash was stored in Redis.
// That made auth COMPLETELY BROKEN whenever Redis was unavailable (free-tier
// Render, missing REDIS_URL, Redis restart) because validateRefreshToken
// failed-closed and always returned false.
//
// Now refresh tokens are signed JWTs verified with JWT_REFRESH_SECRET.
// Validation is stateless. Redis is used only for optional revocation on logout.

const REFRESH_TOKEN_TTL_SECONDS = 7 * 24 * 60 * 60; // 7 days

/**
 * Creates a signed JWT access token.
 */
export function createAccessToken(): string {
    return jwt.sign(
        { role: "admin" },
        env.JWT_SECRET,
        { expiresIn: "15m" }
    );
}

/**
 * Creates a signed JWT refresh token with a unique family ID for rotation tracking.
 */
export function createRefreshToken(familyId?: string): string {
    return jwt.sign(
        { role: "admin", type: "refresh", fid: familyId || crypto.randomUUID() },
        env.JWT_REFRESH_SECRET,
        { expiresIn: "7d" }
    );
}

/**
 * Validates a refresh token JWT and checks against the revocation list.
 */
interface RefreshTokenPayload {
    role: string;
    type: string;
    fid: string;
    iat: number;
    exp: number;
}

export async function validateRefreshToken(token: string): Promise<boolean> {
    // 1. Verify signature and expiry
    let decoded: RefreshTokenPayload;
    try {
        decoded = jwt.verify(token, env.JWT_REFRESH_SECRET) as RefreshTokenPayload;
    } catch {
        return false;
    }

    if (!redis) return true;

    try {
        const tokenHash = crypto.createHash("sha256").update(token).digest("hex");
        
        // 2. Check if this SPECIFIC token is revoked
        const isRevoked = await redis.get(`refresh_revoked:${tokenHash}`);
        if (isRevoked) {
            // SECURITY: REUSE DETECTED. Revoke the entire family (A3).
            if (decoded.fid) {
                await redis.set(`refresh_family_revoked:${decoded.fid}`, "1", "EX", REFRESH_TOKEN_TTL_SECONDS);
                logger.error({ context: "auth", familyId: decoded.fid }, "Refresh token reuse detected. Revoking token family.");
            }
            return false;
        }

        // 3. Check if the FAMILY is revoked
        if (decoded.fid) {
            const isFamilyRevoked = await redis.get(`refresh_family_revoked:${decoded.fid}`);
            if (isFamilyRevoked) {
                logger.warn({ context: "auth", familyId: decoded.fid }, "Attempted use of token from revoked family");
                return false;
            }
        }
    } catch (err) {
        logger.error({ context: "auth", error: err }, "Redis unavailable during revocation check — failing closed");
        return false; 
    }

    return true;
}

/**
 * Revokes a refresh token and optionally its entire family.
 */
export async function revokeRefreshToken(token: string, revokeFamily = false): Promise<void> {
    if (!redis) return;
    try {
        const decoded = jwt.decode(token) as { fid?: string } | null;
        const tokenHash = crypto.createHash("sha256").update(token).digest("hex");
        
        await redis.set(`refresh_revoked:${tokenHash}`, "1", "EX", REFRESH_TOKEN_TTL_SECONDS);
        
        if (revokeFamily && decoded?.fid) {
            await redis.set(`refresh_family_revoked:${decoded.fid}`, "1", "EX", REFRESH_TOKEN_TTL_SECONDS);
        }
    } catch (err) {
        logger.error({ context: "auth", error: err }, "Failed to revoke refresh token");
    }
}

/**
 * Checks if the request is authenticated via JWT or API Key without throwing an error
 */
export async function checkAuthStatus(req: Request): Promise<boolean> {
    let token: string | undefined;

    const authHeader = req.headers.authorization;
    if (authHeader && authHeader.startsWith("Bearer ")) {
        token = authHeader.substring(7);
    } else if (req.cookies && req.cookies.auth_token) {
        token = req.cookies.auth_token;
    }

    if (token) {
        if (redis) {
            const isBlacklisted = await redis.get(`blacklist:${token}`);
            if (isBlacklisted) return false;
        }
        try {
            jwt.verify(token, env.JWT_SECRET);
            return true;
        } catch (err) {
            return false;
        }
    }

    return false;
}

/**
 * Middleware to check for admin authentication via JWT or API Key
 */


export const isAuthenticated = async (req: Request, res: Response, next: NextFunction) => {
    let token: string | undefined;

    // 1. Check for Bearer token in Authorization header
    const authHeader = req.headers.authorization;
    if (authHeader && authHeader.startsWith("Bearer ")) {
        token = authHeader.substring(7);
    }
    // 2. Check for token in auth_token cookie
    else if (req.cookies && req.cookies.auth_token) {
        token = req.cookies.auth_token;
    }

    if (token) {
        // Check if token is blacklisted in Redis
        if (redis) {
            const isBlacklisted = await redis.get(`blacklist:${token}`);
            if (isBlacklisted) {
                return res.status(401).json({ message: "Token has been revoked. Please login again." });
            }
        }

        try {
            const result = jwt.verify(token, env.JWT_SECRET);

            // Standard JWT payload schema
            const tokenSchema = z.object({
                role: z.string(),
                iat: z.number().optional(),
                exp: z.number().optional()
            }).passthrough();

            const parsed = tokenSchema.safeParse(result);
            if (!parsed.success) {
                return res.status(401).json({ message: "Invalid token payload" });
            }

            const decoded = parsed.data;

            // Attach decoded token to request with proper typing
            req.user = {
                role: decoded.role,
                token: token,
                via: authHeader ? "bearer" : "cookie"
            };
            return next();
        } catch (err) {
            if (err instanceof jwt.TokenExpiredError || err instanceof jwt.JsonWebTokenError) {
                return res.status(401).json({ message: "Invalid or expired token" });
            } else {
                return res.status(401).json({ message: "Token verification failed" });
            }
        }
    }

    res.status(401).json({ message: "Unauthorized. Please provide a valid token." });
};

import { z } from "zod";
import dotenv from "dotenv";
import path from "path";
import { fileURLToPath } from "url";
import fs from "fs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// In production (e.g. Render), env vars come from the platform — .env files are gitignored.
// Only load .env files if they exist on disk (local development).
const rootDir = process.cwd();
const envFile = process.env.NODE_ENV === "production" ? ".env.production" : ".env";
const envPath = path.join(rootDir, envFile);

if (fs.existsSync(envPath)) {
    process.stdout.write(`[ENV] Loading variables from: ${envPath}\n`);
    dotenv.config({ path: envPath });
} else {
    // Try fallback .env in root
    const fallback = path.join(rootDir, ".env");
    if (fs.existsSync(fallback)) {
        process.stdout.write(`[ENV] Loading variables from fallback: ${fallback}\n`);
        dotenv.config({ path: fallback });
    } else {
        console.warn("[ENV] No .env file found in root. Relying on platform environment variables.");
    }
}

const envSchema = z.object({
    NODE_ENV: z.enum(["development", "production", "test"]).default("development"),
    PORT: z.string().transform(Number).default("5000"),
    DATABASE_URL: z.string().url("Valid DATABASE_URL is required"),
    RESEND_API_KEY: z.string().optional(),
    REDIS_URL: z.string().optional(),
    FRONTEND_URL: z.string().optional(),
    JWT_SECRET: z.string().min(64, "JWT_SECRET must be at least 64 characters"),
    JWT_REFRESH_SECRET: z.string().min(64, "JWT_REFRESH_SECRET must be at least 64 characters"),
    ADMIN_PASSWORD: z.string().min(16, "ADMIN_PASSWORD must be at least 16 characters"),
    ADMIN_EMAIL: z.string().email(),
    CONTACT_EMAIL: z.string().email(),
    GEMINI_API_KEY: z.string().optional(),
    OPENROUTER_API_KEY: z.string().optional(),
    CLOUDINARY_CLOUD_NAME: z.string().optional(),
    CLOUDINARY_API_KEY: z.string().optional(),
    CLOUDINARY_API_SECRET: z.string().optional(),
    LOG_LEVEL: z.enum(["trace", "debug", "info", "warn", "error", "fatal"]).default("info"),
    SENTRY_DSN: z.string().optional(),
    SENTRY_ENVIRONMENT: z.string().optional(),
    RENDER_DEPLOY_HOOK_URL: z.string().url().optional(),
    BACKEND_RENDER_URL: z.string().url().optional(),
    GITHUB_USERNAME: z.string().optional(),
    GITHUB_TOKEN: z.string().optional(),
});

export type Env = z.infer<typeof envSchema>;

function validateEnv(): Env {
    try {
        const parsed = envSchema.parse(process.env);

        if (parsed.NODE_ENV === "production") {
            if (!parsed.RESEND_API_KEY) {
                console.warn("⚠️  [ENV] RESEND_API_KEY not set. Email sending will fail in production.");
            }
        }

        return parsed;
    } catch (err) {
        if (err instanceof z.ZodError) {
            const missing = err.errors.map((e) => `${e.path.join(".")}: ${e.message}`).join(", ");
            process.stderr.write(`❌ [ENV] Environment validation failed: ${missing}\n`);
            process.stderr.write("💡 Please check your .env file and ensure all required variables are set correctly.\n");
            process.exit(1);
        }
        throw err;
    }
}

// Export a singleton validated env object
export const env = validateEnv();

import express, { type Request, Response, NextFunction } from "express";
import * as Sentry from "@sentry/node";
/**
 * Main Entry Point - System Stabilized
 */
import { env } from "./env.js";
import { createServer } from "http";
import cors from "cors";
import helmet from "helmet";
import { registerRoutes } from "./routes.js";
import compression from "compression";
import cookieParser from "cookie-parser";
import { seedDatabase } from "./seed.js";

import { checkDatabaseHealth } from "./db.js";
import { emailQueue, emailWorker, scopeQueue, scopeWorker, initQueues } from "./lib/queue.js";
import { redis, RedisClient } from "./lib/redis.js"; // Import redis instance and health checker
import { logger } from "./lib/logger.js";
import { bootstrapDatabaseSchema } from "./lib/schema-bootstrap.js";
import { nonceMiddleware } from "./middleware/nonce.js";

import { globalLimiter } from "./lib/rate-limit.js";

import { randomUUID } from "crypto";

const app = express();
// NOTE: "trust proxy 1" assumes exactly ONE proxy tier (Render's load balancer).
// If topology changes (e.g. Cloudflare + Render = 2 proxies), this must be updated
// to the correct number, otherwise rate-limiting will use the proxy IP instead of the client IP.
app.set("trust proxy", 1);
const httpServer = createServer(app);

// Request Tracing and Types are handled via src/types/express.d.ts

// Request Tracing
app.use((req: Request, res: Response, next: NextFunction) => {
  req.id = randomUUID();
  res.setHeader("X-Request-ID", req.id);
  next();
});

const allowedOrigins = [
  "http://localhost:5173",
  "http://localhost:5174",
  "http://localhost:4173",
  "https://abdheshsah.com.np",
  "https://portfolio-frontend-h4f2.onrender.com",
  process.env.FRONTEND_URL,
  ...(process.env.NODE_ENV !== "production" ? [
    "http://localhost:3000",
    "http://localhost:8080",
  ] : []),
].filter((origin): origin is string => Boolean(origin));

app.use(compression());
app.use(cookieParser());
app.use(nonceMiddleware);

app.use("/api/v1", globalLimiter);

// Harden CORS
app.use(
  cors((req: Request, callback: (err: Error | null, options?: cors.CorsOptions) => void) => {
    const origin = req.header("Origin");

    // Allow non-browser requests (health checks, monitoring, cURL) — they have no Origin
    if (!origin) {
      const secFetch = req.header("sec-fetch-site");
      // Allow if it's not a browser request or if it's a same-origin request (proxy)
      if (secFetch && secFetch !== 'none' && secFetch !== 'same-origin') {
        logger.warn({
          path: req.path,
          secFetch,
          userAgent: req.header("user-agent"),
          requestId: req.id
        }, "Browser-like request missing Origin header");

        return callback(null, { origin: false });
      }
      return callback(null, { origin: true, credentials: true });
    }

    const isAllowed = allowedOrigins.includes(origin) ||
      (process.env.NODE_ENV !== "production" && origin.startsWith("http://localhost:")) ||
      (process.env.BACKEND_RENDER_URL ? origin === process.env.BACKEND_RENDER_URL : false);

    if (isAllowed) {
      callback(null, {
        origin: true,
        credentials: true,
        methods: ["GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS"],
        allowedHeaders: ["Content-Type", "Authorization", "X-CSRF-Token", "x-client-token"]
      });
    } else {
      logger.warn({ origin }, "CORS blocked origin");
      callback(null, { origin: false });
    }
  })
);


// Tighten Helmet CSP with Nonces
app.use(
  helmet({
    hidePoweredBy: true, // Remove X-Powered-By in all environments
    contentSecurityPolicy: {
      useDefaults: true,
      directives: {
        "default-src": ["'self'"],
        "script-src": [
          "'self'",
          "https://www.googletagmanager.com",
          "https://infird.com",
          (_req, res) => `'nonce-${(res as any).locals.nonce}'`
        ],
        "object-src": ["'none'"],
        "connect-src": [
          "'self'",
          "https://api.github.com",
          ...(process.env.BACKEND_URL ? [process.env.BACKEND_URL] : []),
          "https://www.google-analytics.com",
          "https://region1.google-analytics.com"
        ],
        "img-src": [
          "'self'",
          "data:",
          "https:",
          "http:",
          "https://res.cloudinary.com",
          "https://*.cloudinary.com",
        ],
        "style-src": [
          "'self'",
          "https://fonts.googleapis.com",
          "https://api.fontshare.com",
          (req, res) => `'nonce-${(res as any).locals.nonce}'`
        ],
        "font-src": ["'self'", "https://fonts.gstatic.com", "https://cdn.fontshare.com"],
        "frame-ancestors": ["'none'"],
        "form-action": ["'self'"],
        "report-uri": ["/api/v1/csp-report"],
      },
    },
    crossOriginEmbedderPolicy: process.env.NODE_ENV === "production",
    crossOriginOpenerPolicy: process.env.NODE_ENV === "production",
    crossOriginResourcePolicy: { policy: "cross-origin" },
    strictTransportSecurity: process.env.NODE_ENV === "production" ? {
      maxAge: 63072000,
      includeSubDomains: true,
      preload: true,
    } : false,
  })
);

// Reduce Payload Limits
app.use(
  express.json({
    limit: "1mb",
    verify: (req: Request, _res: Response, buf: Buffer) => {
      req.rawBody = buf;
    },
  })
);
app.use(express.urlencoded({ extended: false, limit: "1mb" }));

// Request Logger with ID
app.use((req: Request, res: Response, next: NextFunction) => {
  const start = Date.now();
  res.on("finish", () => {
    if (req.path.startsWith("/api")) {
      const duration = Date.now() - start;
      logger.info({
        requestId: req.id,
        method: req.method,
        path: req.path,
        status: res.statusCode,
        duration: `${duration}ms`,
      }, `Request processed`);
    }
  });
  next();
});

// Root route — friendly landing for direct visits
app.get("/", (_req: Request, res: Response) => {
  res.json({
    name: "Portfolio API",
    version: "2.0.0",
    status: "running",
    docs: "/health for health check, /api/* for API endpoints",
  });
});

// Lightweight liveness probe — used by Render's deploy health check.
// Must NOT touch the database so it stays fast even when Neon is cold.
app.get("/ping", (_req: Request, res: Response) => {
  res.status(200).json({ status: "ok" });
});

// Sentry debug route (for verifying error capture pipeline)
// Guarded to only run in development/staging, never production
if (process.env.NODE_ENV !== "production") {
  app.get("/api/v1/debug-sentry", function mainHandler(_req: Request, _res: Response) {
    throw new Error("My first Sentry error!");
  });
}

async function getRedisHealthSafe(): Promise<{ healthy: boolean; message: string }> {
  try {
    return await RedisClient.checkHealth();
  } catch (error: unknown) {
    return {
      healthy: false,
      message: error instanceof Error ? error.message : "Redis health check failed",
    };
  }
}

// Readiness / deep health check — includes database connectivity.
// Returns 200 even if DB is waking up, with a "degraded" flag,
// so Render doesn't mark the deploy as failed during Neon cold starts.
app.get("/health", async (_req: Request, res: Response) => {
  const dbHealth = await checkDatabaseHealth();
  const redisHealth = await getRedisHealthSafe();

  const isHealthy = dbHealth.healthy && redisHealth.healthy;

  res.status(200).json({
    status: isHealthy ? "healthy" : "degraded",
    database: dbHealth.healthy ? "connected" : "reconnecting",
    redis: redisHealth.healthy ? "connected" : "reconnecting",
    environment: process.env.NODE_ENV || "development",
    ...(process.env.NODE_ENV === "development" && {
      timestamp: new Date().toISOString(),
      details: {
        database: dbHealth.message,
        redis: redisHealth.message
      }
    })
  });
});


function setupGracefulShutdown() {
  const shutdown = async (signal: string) => {
    logger.info({ context: "shutdown" }, `${signal} received, shutting down...`);

    // Close HTTP server first to stop accepting new requests
    httpServer.close(() => {
      logger.info({ context: "shutdown" }, "HTTP server closed");
    });

    // Force exit if shutdown takes too long (must be set before any await)
    const forceTimer = setTimeout(() => {
      logger.info({ context: "shutdown" }, "Forced shutdown due to timeout");
      process.exit(1);
    }, 10000);
    forceTimer.unref();

    try {
      // Close database pool
      const { closePool } = await import("./db.js");
      await closePool();
      logger.info({ context: "shutdown" }, "Database pool closed");

      try {
        if (emailQueue) await emailQueue.close();
        if (emailWorker) await emailWorker.close();
        if (scopeQueue) await scopeQueue.close();
        if (scopeWorker) await scopeWorker.close();

        // Disconnect main Redis client
        if (redis) {
          await redis.quit();
        }
        logger.info({ context: "shutdown" }, "Redis and queues closed");
      } catch (qErr) {
        logger.error({ context: "shutdown", error: qErr }, `Error closing Redis/Queue`);
      }

      process.exit(0);
    } catch (err) {
      logger.error({ context: "shutdown", error: err }, `Error during shutdown`);
      process.exit(1);
    }
  };

  process.on("SIGTERM", () => shutdown("SIGTERM"));
  process.on("SIGINT", () => shutdown("SIGINT"));
}

// ==================== MAIN STARTUP ====================
async function startServer() {
  try {
    logger.info({ context: "startup" }, "Starting server...");

    // ── 1. Bind the port FIRST so Render detects the service immediately ──
    //    Static routes (/, /ping) are already registered above and will respond
    //    while the rest of the startup continues in the background.
    const port = parseInt(process.env.PORT || "5000", 10);
    const host = "0.0.0.0";

    await new Promise<void>((resolve) => {
      httpServer.listen(port, host, () => {
        logger.info({ context: "startup", port, host }, `✓ Server listening on ${host}:${port}`);
        resolve();
      });
    });

    // ── 1.1. Initialize background queues and workers ──
    // Deferring this until after port binding ensures the service is "up" in Render's view
    // and reduces congestion during the initial boot sequence.
    initQueues();

    // ── 2. Ensure database is ready before proceeding ──
    logger.info({ context: "startup" }, "📍 Ensuring database is ready (waiting for potential cold start)...");
    const maxAttempts = 10;
    let attempts = 0;
    let dbReady = false;

    while (attempts < maxAttempts && !dbReady) {
      const health = await checkDatabaseHealth();
      if (health.healthy) {
        dbReady = true;
      } else {
        attempts++;
        if (attempts < maxAttempts) {
          logger.info({ context: "startup" }, `📍 Database not ready (${health.message}), retrying (${attempts}/${maxAttempts})...`);
          await new Promise(resolve => setTimeout(resolve, 2000));
        }
      }
    }

    if (!dbReady) {
      logger.error({ context: "startup" }, "❌ Database failed to become ready after multiple attempts. Shutting down...");
      process.exit(1);
    }
    logger.info({ context: "startup" }, "✓ Database is ready");

    // ── 2.1. Run database migrations ──
    logger.info({ context: "startup" }, "📍 Running database migrations...");
    try {
      await bootstrapDatabaseSchema();
      logger.info({ context: "startup" }, "✓ Migrations complete");
    } catch (migErr) {
      logger.error({ context: "startup", error: migErr }, "❌ Migration failed");
      // Migration failure is critical in production
      if (process.env.NODE_ENV === "production") {
        process.exit(1);
      }
    }

    // ── 2.2. Ensure schema compatibility for production safety ──

    // Controlled seeding: REMOVED from application startup for production safety.
    // Seeding should be performed as a separate build step or CLI command to prevent 
    // accidental data loss (A5).
    logger.info({ context: "startup" }, "ℹ️ Auto-seeding check skipped. Use 'npm run seed' for manual data initialization.");

    // ── 3. Register API routes ──
    logger.info({ context: "startup" }, "📍 Registering API routes...");
    registerRoutes(app);
    logger.info({ context: "startup" }, "✓ API routes registered");

    // Sentry Error Handler (must be before custom error handlers)
    if (env.SENTRY_DSN) {
      Sentry.setupExpressErrorHandler(app);
    }

    // Sanitize Global Error Handler
    app.use(
      (err: Error & { status?: number; statusCode?: number }, req: Request, res: Response, _next: NextFunction) => {
        const status = err.status || err.statusCode || 500;
        const message = (status === 500 && process.env.NODE_ENV !== "development") ? "Internal Server Error" : err.message;

        logger.error({
          requestId: req.id,
          status,
          error: err.message,
          stack: env.NODE_ENV === "development" ? err.stack : undefined,
        }, `Global Error Handler`);


        if (env.SENTRY_DSN && status >= 500) {
          Sentry.captureException(err);
        }

        res.status(status).json({
          error: {
            message,
            status,
            ...(process.env.NODE_ENV === "development" && { stack: err.stack }),
          }
        });
      }
    );

    // SETUP GRACEFUL SHUTDOWN
    setupGracefulShutdown();

    logger.info({ context: "startup" }, "✓ Server fully ready");
  } catch (error) {
    logger.fatal({ context: "startup", error }, `❌ STARTUP FAILED`);
    process.exit(1);
  }
}

// Run the startup
startServer();

import { Request, Response, NextFunction } from "express";

/**
 * Error handler wrapper for async routes
 */
export function asyncHandler(fn: (req: Request, res: Response, next: NextFunction) => Promise<any>) {
    return (req: Request, res: Response, next: NextFunction): void => {
        Promise.resolve(fn(req, res, next)).catch(next);
    };
}

import { Queue, Worker, Job } from "bullmq";
import { Redis } from "ioredis";
import { Resend } from "resend";
import { env } from "../env.js";
import { logger } from "./logger.js";
import { isLocalRedisUrl, formatRedisUrlForLog } from "./redis.js";
import { createScopeWorker } from "../workers/scope.worker.js";
import { escapeHtml } from "./escape.js";
import { emailTemplateService } from "../services/email-template.service.js";

// BullMQ requires dedicated ioredis connections with maxRetriesPerRequest: null.
// Queue and Worker each need their own connection (BullMQ internal requirement).
// These are intentionally separate from the app-level redis singleton in redis.ts.
function getRedisConnection() {
    return new Redis(env.REDIS_URL || "redis://localhost:6379", {
        maxRetriesPerRequest: null, // BullMQ requires this to be null
        retryStrategy(times) {
            return Math.min(times * 50, 2000);
        }
    });
}

// bullmq bundles its own ioredis — cast via the ConnectionOptions shape it actually expects
// eslint-disable-next-line @typescript-eslint/no-explicit-any -- ioredis version mismatch; pinned in root overrides
function toBullMQConnection(r: ReturnType<typeof getRedisConnection>) {
    return r as unknown as import("bullmq").ConnectionOptions;
}

// Ensure BullMQ is only active if REDIS validation passes or running locally
const isProd = process.env.NODE_ENV === "production";
const hasRedisUrl = !!env.REDIS_URL;
const isProdLocalRedis = isProd && hasRedisUrl && isLocalRedisUrl(env.REDIS_URL as string);

const canUseRedis = !isProd || (hasRedisUrl && !isProdLocalRedis);

export let emailQueue: Queue | null = null;
export let scopeQueue: Queue | null = null;
export let emailWorker: Worker | null = null;
export let scopeWorker: Worker | null = null;

/** Shared Resend client — instantiated once when queues initialize, not per-job */
let resend: Resend | null = null;

/** Simple in-memory template cache (Finding #16) */
let templateCache: any[] | null = null;
let lastTemplateFetch = 0;
const TEMPLATE_CACHE_TTL = 60 * 1000; // 1 minute

async function getCachedTemplates() {
    const now = Date.now();
    if (!templateCache || (now - lastTemplateFetch > TEMPLATE_CACHE_TTL)) {
        templateCache = await emailTemplateService.getAll();
        lastTemplateFetch = now;
    }
    return templateCache;
}

interface EmailParams {
    from: string;
    to: string;
    subject: string;
    html: string;
    attachments?: any[];
}

/** Strategy Pattern for different email types (Finding #15) */
const EMAIL_STRATEGIES: Record<string, (payload: any) => Promise<EmailParams> | EmailParams> = {
    "contact-notification": (payload) => ({
        from: env.CONTACT_EMAIL,
        to: payload.targetEmail,
        subject: `Portfolio Message: ${escapeHtml(payload.message.subject || "No Subject")}`,
        html: `
            <h3>New Message from Portfolio</h3>
            <p><strong>Name:</strong> ${escapeHtml(payload.message.name)}</p>
            <p><strong>Email:</strong> ${escapeHtml(payload.message.email)}</p>
            <p><strong>Subject:</strong> ${escapeHtml(payload.message.subject || "")}</p>
            <hr/>
            <p><strong>Message:</strong></p>
            <p style="white-space: pre-wrap;">${escapeHtml(payload.message.message)}</p>
        `,
    }),
    "admin-reply": (payload) => ({
        from: env.CONTACT_EMAIL,
        to: payload.to,
        subject: payload.subject,
        html: payload.html,
    }),
    "admin-notification": (payload) => ({
        from: env.CONTACT_EMAIL,
        to: payload.to || env.ADMIN_EMAIL,
        subject: payload.subject,
        html: payload.html,
        attachments: payload.attachments,
    }),
    "client-notification": (payload) => ({
        from: env.CONTACT_EMAIL,
        to: payload.to,
        subject: payload.subject,
        html: payload.html,
        attachments: payload.attachments,
    }),
    "auto-reply": async (payload) => {
        const { message } = payload;
        const templates = await getCachedTemplates();
        const dynamicTemplate = templates.find(t => 
            t.name.toLowerCase().includes('auto-reply') || 
            t.name.toLowerCase().includes('inquiry')
        );

        let subject = "Thank you for reaching out!";
        let html = `
            <p>Hi ${escapeHtml(message.name)},</p>
            <p>Thank you for your message. I have received it and will get back to you as soon as possible.</p>
            <p>Best regards,<br/>Portfolio Admin</p>
        `;

        if (dynamicTemplate) {
            subject = dynamicTemplate.subject;
            html = dynamicTemplate.body.replace(/\{name\}/g, escapeHtml(message.name));
        }

        return {
            from: env.CONTACT_EMAIL,
            to: message.email,
            subject,
            html,
        };
    }
};

export function initQueues() {
    if (isProd && (!hasRedisUrl || isProdLocalRedis)) {
        logger.warn(
            {
                context: "queue",
                redisConfigured: hasRedisUrl,
                redisUrl: formatRedisUrlForLog(env.REDIS_URL),
            },
            "Queue disabled in production: REDIS_URL is missing or points to localhost. Set REDIS_URL to a managed Redis endpoint (recommended rediss://...) or unset REDIS_URL to disable background jobs intentionally."
        );
    }

    if (!canUseRedis) return;

    logger.info({ context: "queue" }, "📍 Initializing BullMQ queues and workers...");

    const defaultJobOptions = {
        attempts: 5,
        backoff: {
            type: "exponential",
            delay: 1000,
        },
        removeOnComplete: true,
        removeOnFail: false, // Keep failed jobs for manual inspection
    };

    emailQueue = new Queue("email", {
        connection: toBullMQConnection(getRedisConnection()),
        defaultJobOptions
    });

    scopeQueue = new Queue("scope", {
        connection: toBullMQConnection(getRedisConnection()),
        defaultJobOptions
    });

    // Instantiate Resend client once for the lifetime of the worker
    if (env.RESEND_API_KEY) {
        resend = new Resend(env.RESEND_API_KEY);
    }

    emailWorker = new Worker("email", async (job: Job) => {
        const { type, payload } = job.data;

        if (!resend) {
            logger.warn({ context: "queue" }, "Skipping email: RESEND_API_KEY not set");
            return;
        }

        const strategy = EMAIL_STRATEGIES[type];
        if (!strategy) {
            throw new Error(`Unknown job type: ${type}`);
        }

        const params = await strategy(payload);
        const { data, error } = await resend.emails.send(params);

        if (error) {
            throw new Error(`Failed to send ${type}: ${error.message}`);
        }
        return data;
    }, {
        connection: toBullMQConnection(getRedisConnection())
    });

    scopeWorker = createScopeWorker(getRedisConnection() as unknown as import("ioredis").Redis);

    if (emailWorker) {
        emailWorker.on("completed", (job) => {
            logger.info({ context: "queue", jobId: job.id, type: job.data.type }, "Job completed successfully");
        });

        emailWorker.on("failed", (job, err) => {
            logger.error({ context: "queue", jobId: job?.id, type: job?.data?.type, error: err }, "Job failed");
        });
    }

    logger.info({ context: "queue" }, "✓ BullMQ queues and workers initialized");
}

import { migrate } from "drizzle-orm/node-postgres/migrator";
import type { PoolClient } from "pg";
import { db, pool } from "../db.js";
import { logger } from "./logger.js";
import path from "path";
import fs from "fs";

const STARTUP_MIGRATIONS_FOLDER = path.resolve(process.cwd(), "drizzle/migrations");

function parseBoolean(value: unknown): boolean | null {
    if (typeof value === "boolean") return value;
    if (typeof value !== "string") return null;

    const normalized = value.trim().toLowerCase();
    if (["true", "1", "yes", "y", "on"].includes(normalized)) return true;
    if (["false", "0", "no", "n", "off"].includes(normalized)) return false;
    return null;
}

async function runBestEffortMigrations() {
    try {
        logger.info({ context: "schema-bootstrap", path: STARTUP_MIGRATIONS_FOLDER }, "📍 Checking migrations folder...");

        if (!fs.existsSync(STARTUP_MIGRATIONS_FOLDER)) {
            throw new Error(`Migrations folder not found: ${STARTUP_MIGRATIONS_FOLDER}`);
        }

        await migrate(db, { migrationsFolder: STARTUP_MIGRATIONS_FOLDER });
        logger.info({ context: "schema-bootstrap" }, "✓ Migration check completed");
    } catch (error: unknown) {
        const message = error instanceof Error ? error.message : "Unknown error";
        const stack = error instanceof Error ? error.stack : undefined;
        logger.error(
            { context: "schema-bootstrap", error: message, stack },
            "❌ Migration step failed"
        );
        // We still continue to applyConsistencyChecks which might create basic tables
    }
}

