async function applyConsistencyChecks() {
    const client = await pool.connect();
    try {
        await client.query("BEGIN");
        await ensureSiteSettingsInit(client);
        await client.query("COMMIT");
        logger.info({ context: "schema-bootstrap" }, "✓ Consistency checks complete");
    } catch (error) {
        await client.query("ROLLBACK");
        logger.error({ context: "schema-bootstrap", error }, "Consistency check failed");
        // Don't throw here to allow app to start if migrations succeeded
    } finally {
        client.release();
    }
}

export async function bootstrapDatabaseSchema() {
    // 1. Run migrations first (primary method)
    await runBestEffortMigrations();

    // 2. Run light consistency checks/init (secondary safety net)
    await applyConsistencyChecks();
}

import { describe, it, expect, vi, beforeEach } from "vitest";
import { Request, Response, NextFunction } from "express";
import { cachePublic } from "../middleware/cache.js";

describe("cachePublic middleware", () => {
    let mockRes: Partial<Response>;
    let mockNext: NextFunction;

    function makeReq(overrides: Partial<Request> = {}): Partial<Request> {
        return {
            method: "GET",
            cookies: {},
            headers: {},
            ...overrides,
        };
    }

    beforeEach(() => {
        mockRes = {
            set: vi.fn().mockReturnThis() as any,
        };
        mockNext = vi.fn();
    });

    it("sets Cache-Control header for GET requests", () => {
        const middleware = cachePublic(300);
        const req = makeReq();

        middleware(req as Request, mockRes as Response, mockNext);

        expect(mockRes.set).toHaveBeenCalledWith(
            "Cache-Control",
            "public, max-age=300, stale-while-revalidate=60"
        );
        expect(mockNext).toHaveBeenCalled();
    });

    it("uses custom maxAge value", () => {
        const middleware = cachePublic(600);
        const req = makeReq();

        middleware(req as Request, mockRes as Response, mockNext);

        expect(mockRes.set).toHaveBeenCalledWith(
            "Cache-Control",
            "public, max-age=600, stale-while-revalidate=60"
        );
    });

    it("skips non-GET requests", () => {
        const middleware = cachePublic(300);
        const req = makeReq({ method: "POST" });

        middleware(req as Request, mockRes as Response, mockNext);

        expect(mockRes.set).not.toHaveBeenCalled();
        expect(mockNext).toHaveBeenCalled();
    });

    it("skips when auth_token cookie is present", () => {
        const middleware = cachePublic(300);
        const req = makeReq({ cookies: { auth_token: "abc123" } });

        middleware(req as Request, mockRes as Response, mockNext);

        expect(mockRes.set).not.toHaveBeenCalled();
        expect(mockNext).toHaveBeenCalled();
    });

    it("skips when authorization header is present", () => {
        const middleware = cachePublic(300);
        const req = makeReq({ headers: { authorization: "Bearer token" } });

        middleware(req as Request, mockRes as Response, mockNext);

        expect(mockRes.set).not.toHaveBeenCalled();
        expect(mockNext).toHaveBeenCalled();
    });

    it("uses default maxAge of 300 when no argument given", () => {
        const middleware = cachePublic();
        const req = makeReq();

        middleware(req as Request, mockRes as Response, mockNext);

        expect(mockRes.set).toHaveBeenCalledWith(
            "Cache-Control",
            "public, max-age=300, stale-while-revalidate=60"
        );
    });
});

import { describe, it, expect, vi, beforeEach } from "vitest";
import type { Request, Response, NextFunction } from "express";

const { csrfProtection, generateCsrfToken } = await import("./csrf.js");

function mockReq(overrides: Partial<Request> = {}): Request {
    return {
        method: "POST",
        cookies: {},
        headers: {},
        ...overrides,
    } as unknown as Request;
}

function mockRes(): { res: Response; statusCode: number; body: any } {
    const ctx = { statusCode: 0, body: null as any };
    const res = {
        status(code: number) {
            ctx.statusCode = code;
            return res;
        },
        json(data: any) {
            ctx.body = data;
            return res;
        },
    } as unknown as Response;
    return { res, ...ctx, get statusCode() { return ctx.statusCode; }, get body() { return ctx.body; } };
}

describe("csrfProtection middleware", () => {
    let next: NextFunction;

    beforeEach(() => {
        next = vi.fn();
    });

    it("skips GET requests", () => {
        const req = mockReq({ method: "GET" });
        const { res } = mockRes();
        csrfProtection(req, res, next);
        expect(next).toHaveBeenCalled();
    });

    it("skips HEAD requests", () => {
        const req = mockReq({ method: "HEAD" });
        const { res } = mockRes();
        csrfProtection(req, res, next);
        expect(next).toHaveBeenCalled();
    });

    it("skips OPTIONS requests", () => {
        const req = mockReq({ method: "OPTIONS" });
        const { res } = mockRes();
        csrfProtection(req, res, next);
        expect(next).toHaveBeenCalled();
    });

    it("skips unauthenticated POST requests (no auth_token)", () => {
        const req = mockReq({ method: "POST", cookies: {} });
        const { res } = mockRes();
        csrfProtection(req, res, next);
        expect(next).toHaveBeenCalled();
    });

    it("returns 403 when authenticated POST has no CSRF token", () => {
        const r = mockRes();
        const req = mockReq({
            method: "POST",
            cookies: { auth_token: "jwt-token" },
            headers: {},
        });
        csrfProtection(req, r.res, next);
        expect(next).not.toHaveBeenCalled();
        expect(r.statusCode).toBe(403);
        expect(r.body).toEqual({ message: "Invalid CSRF token" });
    });

    it("returns 403 when CSRF header does not match cookie", () => {
        const r = mockRes();
        const req = mockReq({
            method: "POST",
            cookies: { auth_token: "jwt", csrf_token: "token-a" },
            headers: { "x-csrf-token": "token-b" },
        });
        csrfProtection(req, r.res, next);
        expect(next).not.toHaveBeenCalled();
        expect(r.statusCode).toBe(403);
    });

    it("passes when CSRF header matches cookie", () => {
        const token = generateCsrfToken();
        const req = mockReq({
            method: "POST",
            cookies: { auth_token: "jwt", csrf_token: token },
            headers: { "x-csrf-token": token },
        });
        const { res } = mockRes();
        csrfProtection(req, res, next);
        expect(next).toHaveBeenCalled();
    });

    it("returns 403 for DELETE with mismatched tokens", () => {
        const r = mockRes();
        const req = mockReq({
            method: "DELETE",
            cookies: { auth_token: "jwt", csrf_token: "aaa" },
            headers: { "x-csrf-token": "bbb" },
        });
        csrfProtection(req, r.res, next);
        expect(next).not.toHaveBeenCalled();
        expect(r.statusCode).toBe(403);
    });

    it("passes for PUT with matching tokens", () => {
        const token = "test-csrf-token-123";
        const req = mockReq({
            method: "PUT",
            cookies: { auth_token: "jwt", csrf_token: token },
            headers: { "x-csrf-token": token },
        });
        const { res } = mockRes();
        csrfProtection(req, res, next);
        expect(next).toHaveBeenCalled();
    });
});

describe("generateCsrfToken", () => {
    it("generates a 64-character hex string", () => {
        const token = generateCsrfToken();
        expect(token).toMatch(/^[a-f0-9]{64}$/);
    });

    it("generates unique tokens", () => {
        const tokens = new Set(Array.from({ length: 10 }, () => generateCsrfToken()));
        expect(tokens.size).toBe(10);
    });
});

import { describe, it, expect, vi, beforeEach } from "vitest";
import { Request, Response, NextFunction } from "express";
import { validateBody } from "../middleware/validate.js";
import { z } from "zod";

describe("validateBody middleware", () => {
    let mockReq: Partial<Request>;
    let mockRes: Partial<Response>;
    let mockNext: NextFunction;

    beforeEach(() => {
        mockReq = { body: {} };
        mockRes = {
            status: vi.fn().mockReturnThis() as any,
            json: vi.fn().mockReturnThis() as any,
        };
        mockNext = vi.fn();
    });

    it("passes valid body and calls next", async () => {
        const schema = z.object({ name: z.string() });
        const middleware = validateBody(schema);

        mockReq.body = { name: "test" };
        await middleware(mockReq as Request, mockRes as Response, mockNext);

        expect(mockNext).toHaveBeenCalledWith();
        expect(mockReq.body).toEqual({ name: "test" });
    });

    it("strips unknown properties", async () => {
        const schema = z.object({ name: z.string() }).strict();
        const middleware = validateBody(schema);

        mockReq.body = { name: "test", extra: "nope" };
        await middleware(mockReq as Request, mockRes as Response, mockNext);

        // strict schema should produce a ZodError
        expect(mockRes.status).toHaveBeenCalledWith(400);
        expect(mockRes.json).toHaveBeenCalledWith(
            expect.objectContaining({
                message: "Validation failed",
                errors: expect.arrayContaining([
                    expect.objectContaining({ path: expect.any(String), message: expect.any(String) }),
                ]),
            })
        );
    });

    it("returns 400 with structured errors for missing required fields", async () => {
        const schema = z.object({ name: z.string(), email: z.string().email() });
        const middleware = validateBody(schema);

        mockReq.body = {};
        await middleware(mockReq as Request, mockRes as Response, mockNext);

        expect(mockRes.status).toHaveBeenCalledWith(400);
        const jsonCall = (mockRes.json as any).mock.calls[0][0];
        expect(jsonCall.message).toBe("Validation failed");
        expect(jsonCall.errors).toHaveLength(2);
        expect(jsonCall.errors[0]).toHaveProperty("path");
        expect(jsonCall.errors[0]).toHaveProperty("message");
    });

    it("forwards non-Zod errors to next", async () => {
        const schema = z.object({ name: z.string() });
        const middleware = validateBody(schema);

        // Simulate parseAsync throwing a non-Zod error
        const origParseAsync = schema.parseAsync.bind(schema);
        vi.spyOn(schema, "parseAsync").mockRejectedValueOnce(new Error("Unexpected error"));

        await middleware(mockReq as Request, mockRes as Response, mockNext);

        expect(mockNext).toHaveBeenCalledWith(expect.any(Error));
    });
});

