import { Router } from "express";
import { emailTemplateService } from "../services/email-template.service.js";
import { insertEmailTemplateApiSchema } from "@portfolio/shared";
import { isAuthenticated } from "../auth.js";
import { parseIntParam } from "../lib/params.js";
import { asyncHandler } from "../lib/async-handler.js";
import { z } from "zod";
import { validateBody } from "../middleware/validate.js";
import { recordAudit } from "../lib/audit.js";

export function registerEmailTemplateRoutes(app: Router) {
    // GET /email-templates - List all templates (admin only)
    app.get(
        "/email-templates",
        isAuthenticated,
        asyncHandler(async (_req, res) => {
            const templates = await emailTemplateService.getAll();
            res.json(templates);
        })
    );

    // GET /email-templates/:id - Get single template
    app.get(
        "/email-templates/:id",
        isAuthenticated,
        asyncHandler(async (req, res) => {
            const id = parseIntParam(res, req.params.id, "Invalid template ID");
            if (id === null) return;
            const template = await emailTemplateService.getById(id);
            if (!template) {
                res.status(404).json({
                    success: false,
                    message: "Template not found"
                });
                return;
            }
            res.json(template);
        })
    );

    // POST /email-templates - Create template
    app.post(
        "/email-templates",
        isAuthenticated,
        validateBody(insertEmailTemplateApiSchema),
        asyncHandler(async (req, res) => {
            const template = await emailTemplateService.create(req.body);

            // Audit log (A4)
            recordAudit("CREATE", "email_template", template.id, null, req.body);

            res.status(201).json({
                success: true,
                message: "Email template created successfully",
                data: template
            });
        })
    );

    // PUT /email-templates/:id - Update template
    app.put(
        "/email-templates/:id",
        isAuthenticated,
        validateBody(insertEmailTemplateApiSchema.partial()),
        asyncHandler(async (req, res) => {
            const id = parseIntParam(res, req.params.id, "Invalid template ID");
            if (id === null) return;
            const template = await emailTemplateService.update(id, req.body);

            // Audit log (A4)
            recordAudit("UPDATE", "email_template", id, null, req.body);

            res.json({
                success: true,
                message: "Email template updated successfully",
                data: template
            });
        })
    );

    // DELETE /email-templates/:id - Delete template
    app.delete(
        "/email-templates/:id",
        isAuthenticated,
        asyncHandler(async (req, res) => {
            const id = parseIntParam(res, req.params.id, "Invalid template ID");
            if (id === null) return;
            await emailTemplateService.delete(id);

            // Audit log (A4)
            recordAudit("DELETE", "email_template", id);

            res.status(204).send();
        })
    );
}

import { Router } from "express";
import { articleService } from "../services/article.service.js";
import type { Article } from "@portfolio/shared";
import { escapeXml } from "../lib/xml-utils.js";
import { logger } from "../lib/logger.js";

const feedRoutes = Router();

feedRoutes.get("/feed.xml", async (req: any, res: any) => {
  try {
    const articles = await articleService.getAll("published");
    const siteUrl = process.env.FRONTEND_URL || "https://abdheshsah.com.np";

    let xml = `<?xml version="1.0" encoding="UTF-8" ?>
<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">
  <channel>
    <title>Abdhesh Sah - Portfolio &amp; Blog</title>
    <link>${siteUrl}/blog</link>
    <description>Latest articles and projects from Abdhesh Sah.</description>
    <language>en-us</language>
    <atom:link href="${siteUrl}/api/v1/feed/feed.xml" rel="self" type="application/rss+xml" />
`;

    articles.forEach((article: Article) => {
      const url = escapeXml(`${siteUrl}/blog/${article.slug}`);
      const date = article.publishedAt ? new Date(article.publishedAt).toUTCString() : new Date(article.createdAt).toUTCString();

      xml += `
    <item>
      <title><![CDATA[${article.title}]]></title>
      <link>${url}</link>
      <guid isPermaLink="true">${url}</guid>
      <description><![CDATA[${article.excerpt || article.title}]]></description>
      <pubDate>${date}</pubDate>
    </item>`;
    });

    xml += `
  </channel>
</rss>`;

    res.header("Content-Type", "application/rss+xml");
    res.send(xml);
  } catch (error) {
    logger.error({ context: "feed", error }, "Error generating RSS feed");
    res.status(500).send("Error generating feed");
