import { Router, Request, Response } from "express";
import { z } from "zod";
import { Resend } from "resend";
import { contactLimiter } from "../lib/rate-limit.js";
import { messageService } from "../services/message.service.js";
import { insertMessageApiSchema } from "@portfolio/shared";
import { env } from "../env.js";
import { isAuthenticated } from "../auth.js";
import { asyncHandler } from "../lib/async-handler.js";
import DOMPurify from 'isomorphic-dompurify';
import { emailQueue } from "../lib/queue.js";
import { logger } from "../lib/logger.js";
import { recordAudit } from "../lib/audit.js";
import { parseIntParam } from "../lib/params.js";
import { escapeHtml } from "../lib/escape.js";
import { validateBody } from "../middleware/validate.js";
import { messageSSE } from "../lib/sse.js";
import { notificationService } from "../services/notification.service.js";
import crypto from "crypto";

export function registerMessageRoutes(app: Router) {
    // GET /messages/stream - SSE endpoint for real-time message notifications (admin only)
    app.get(
        "/messages/stream",
        isAuthenticated,
        (req: Request, res: Response) => {
            res.writeHead(200, {
                "Content-Type": "text/event-stream",
                "Cache-Control": "no-cache",
                "Connection": "keep-alive",
                "X-Accel-Buffering": "no", // Disable nginx buffering
            });

            // Send initial connection event
            res.write(`event: connected\ndata: ${JSON.stringify({ status: "ok" })}\n\n`);

            const clientId = crypto.randomUUID();
            messageSSE.addClient(clientId, res);

            req.on("close", () => {
                messageSSE.removeClient(clientId);
            });
        }
    );

    // GET /messages - List all messages (admin only)
    app.get(
        "/messages",
        isAuthenticated,
        asyncHandler(async (_req, res) => {
            const messages = await messageService.getAll();
            res.json(messages);
        })
    );

    // POST /messages/bulk-delete - Bulk delete messages
    app.post(
        "/messages/bulk-delete",
        isAuthenticated,
        asyncHandler(async (req, res) => {
            const schema = z.object({ ids: z.array(z.number()) });
            const { ids } = schema.parse(req.body);
            await messageService.bulkDelete(ids);

            // Audit log (A2)
            recordAudit("DELETE", "message_bulk", undefined, null, { deletedIds: ids });

            res.status(204).send();
        })
    );

    // GET /messages/:id - Get single message
    app.get(
        "/messages/:id",
        isAuthenticated,
        asyncHandler(async (req, res) => {
            const id = parseIntParam(res, req.params.id, "message ID");
            if (id === null) return;
            const message = await messageService.getById(id);
            if (!message) {
                res.status(404).json({ success: false, message: "Message not found" });
                return;
            }
            res.json(message);
        })
    );

    // POST /messages - Create message (contact form)
    app.post(
        "/messages",
        contactLimiter,
        validateBody(insertMessageApiSchema),
        asyncHandler(async (req, res) => {
            try {
                const message = await messageService.create(req.body);
                logger.info({ context: "messages", name: message.name, email: message.email }, "New message received");

                // Emit SSE event for real-time admin notification
                messageSSE.emit("new-message", {
                    id: message.id,
                    name: message.name,
                    subject: message.subject,
                    createdAt: message.createdAt,
                });

                // Send response immediately
                res.status(201).json({
                    success: true,
                    message: "Message sent! We'll get back to you soon.",
                    data: message,
                });

                // Fire and forget notification pipeline (handles queue & fallback)
                notificationService.sendContactNotification(message);
            } catch (error: unknown) {
                if (error instanceof Error && error.message === "Message rejected") {
                    logger.warn({ context: "messages", email: req.body.email }, "Spam blocked (Honeypot filled)");
                    // Fake success to trick the bot
                    res.status(201).json({
                        success: true,
                        message: "Message sent! We'll get back to you soon.",
                        data: { id: 0, message: "blocked" },
                    });
                    return;
                }
                throw error;
            }
        })
    );

    // POST /messages/:id/reply - Reply to a message
    app.post(
        "/messages/:id/reply",
        isAuthenticated,
        asyncHandler(async (req, res) => {
            const id = parseIntParam(res, req.params.id, "message ID");
            if (id === null) return;

            const schema = z.object({
                subject: z.string().min(1),
                body: z.string().min(1),
            });

            const { subject, body } = schema.parse(req.body);

            const message = await messageService.getById(id);
            if (!message) {
                res.status(404).json({ success: false, message: "Message not found" });
                return;
            }

            if (!env.RESEND_API_KEY) {
                res.status(500).json({ success: false, message: "Email service not configured (RESEND_API_KEY missing)" });
                return;
            }

            const resend = new Resend(env.RESEND_API_KEY);

            // Sanitize HTML before sending — block javascript: URIs and enforce secure links
            const sanitizedBody = DOMPurify.sanitize(body, {
                ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'u', 'a', 'ul', 'ol', 'li'],
                ALLOWED_ATTR: ['href', 'target', 'rel'],
                FORBID_ATTR: [],
                ALLOW_DATA_ATTR: false,
            });
            // Post-process: strip javascript: hrefs and enforce rel="noopener noreferrer"
            const safeSanitizedBody = sanitizedBody
                .replace(/href\s*=\s*["']javascript:[^"']*["']/gi, 'href="#"')
                .replace(/<a\b([^>]*?)(\srel="[^"]*")?([^>]*?)>/gi, (match, p1, p2, p3) => {
                    // Remove any existing rel attribute and add the mandatory one
                    return `<a${p1}${p3} rel="noopener noreferrer">`;
                });

            if (emailQueue) {
                try {
                    await emailQueue.add("send-reply-email", {
                        type: "admin-reply",
                        payload: {
                            to: message.email,
                            subject: subject,
                            html: safeSanitizedBody,
                        }
                    });
                    logger.info({ context: "messages", to: message.email }, "Queued reply");

                    // Audit log (A2)
                    recordAudit("CREATE", "message_reply", id, null, { subject });

                    res.json({ success: true, message: "Reply queued successfully" });
                } catch (queueError: any) {
                    logger.error({ context: "messages", to: message.email, error: queueError.message }, "Failed to queue reply");
                    res.status(500).json({ success: false, message: `Failed to queue email: ${queueError.message}` });
                }
            } else {
                res.status(500).json({ success: false, message: "Email queue not configured (Redis required)" });
            }
        })
    );

    // DELETE /messages/:id - Delete message
    app.delete(
        "/messages/:id",
        isAuthenticated,
        asyncHandler(async (req, res) => {
            const id = parseIntParam(res, req.params.id, "message ID");
            if (id === null) return;
            const deleted = await messageService.delete(id);
            if (!deleted) {
                res.status(404).json({ success: false, message: "Message not found" });
                return;
            }

            // Audit log (A2)
            recordAudit("DELETE", "message", id);

            res.status(204).send();
        })
    );
}

import { Router, Request, Response, NextFunction } from "express";
import { z } from "zod";
import { projectService } from "../services/project.service.js";
import { insertProjectApiSchema } from "@portfolio/shared";
import { api } from "@portfolio/shared";
import { isAuthenticated } from "../auth.js";
import { asyncHandler } from "../lib/async-handler.js";
import { parseIntParam } from "../lib/params.js";


import { validateBody } from "../middleware/validate.js";
import { cachePublic } from "../middleware/cache.js";
import { recordAudit } from "../lib/audit.js";
import { logger } from "../lib/logger.js";
import { redis } from "../lib/redis.js";

export function registerProjectRoutes(app: Router) {
  // GET /api/projects - Get all projects
  app.get(
    "/projects",
    cachePublic(600), // Cache for 10 minutes
    asyncHandler(async (req: Request, res: Response) => {
      const sortSchema = z.enum(["views", "default"]).optional().default("default");
      const sortBy = sortSchema.parse(req.query.sort);
      const isSecretMode = req.query.secret === "revealed";

      const projects = isSecretMode
        ? await projectService.getAllAdmin()
        : await projectService.getAll(sortBy);

      res.json(projects);
    })
  );

  // POST /projects - Create project
  app.post(
    "/projects",
    isAuthenticated,
    validateBody(insertProjectApiSchema),
    asyncHandler(async (req, res) => {
      const project = await projectService.create(req.body);
      recordAudit("CREATE", "project", project.id, null, req.body);
      res.status(201).json({
        success: true,
        message: "Project created successfully",
        data: project
      });
    })
  );

  // PUT /projects/reorder - Reorder projects
  app.put(
    "/projects/reorder",
    isAuthenticated,
    asyncHandler(async (req, res) => {
      const schema = z.object({ orderedIds: z.array(z.number()) });
      const { orderedIds } = schema.parse(req.body);
      await projectService.updateReorder(orderedIds);
      recordAudit("UPDATE", "project", undefined, null, { orderedIds });
      res.status(204).send();
    })
  );

  // POST /projects/:id/summary - AI Summary Generation
  app.post(
    "/projects/:id/summary",
    isAuthenticated,
    asyncHandler(async (req, res) => {
      const id = parseIntParam(res, req.params.id, "project ID");
            if (id === null) return;
      const summary = await projectService.generateSummary(id);
      recordAudit("UPDATE", "project", id, null, { summary });
      res.json({ success: true, summary });
    })
  );

  // POST /projects/bulk-delete
  app.post(
    "/projects/bulk-delete",
    isAuthenticated,
    asyncHandler(async (req, res) => {
      const schema = z.object({ ids: z.array(z.number()) });
      const { ids } = schema.parse(req.body);
      await projectService.bulkDelete(ids);
      recordAudit("DELETE", "project", undefined, { ids }, null);
      res.status(204).send();
    })
  );

  // POST /projects/bulk-status
  app.post(
    "/projects/bulk-status",
    isAuthenticated,
    asyncHandler(async (req, res) => {
      const schema = z.object({
        ids: z.array(z.number()),
        status: z.enum(["In Progress", "Completed", "Archived"]),
      });
      const { ids, status } = schema.parse(req.body);
      await projectService.bulkUpdateStatus(ids, status);
      recordAudit("UPDATE", "project", undefined, null, { ids, status });
      res.status(204).send();
    })
  );

  // GET /api/projects/:id - Get project by ID (Moved to bottom)
  app.get(
    "/projects/:id",
    cachePublic(600),
    asyncHandler(async (req, res) => {
      const id = parseIntParam(res, req.params.id, "project ID");
            if (id === null) return;

      const isSecretMode = req.query.secret === "revealed";
      const project = await projectService.getById(id);

      if (!project || (project.isHidden && !isSecretMode)) {
        res.status(404).json({ success: false, message: "Project not found" });
        return;
      }
      res.json(project);

      // Fire-and-forget IP-based deduplication for view counts (1 hour)
      const ip = req.ip || req.headers['x-forwarded-for'] || 'unknown';
      const viewKey = `view:project:${project.id}:ip:${ip}`;

      const r = redis;
      if (r) {
        r.get(viewKey).then((hasViewed: string | null) => {
          if (!hasViewed) {
            projectService.incrementViewCount(project.id).catch((err: any) => {
              logger.error({ context: "project", id: project.id, error: err }, "Failed to increment view count");
            });
            r.set(viewKey, "1", "EX", 3600).catch((err: any) => {
              logger.error({ context: "project", error: err }, "Failed to set view cache");
            });
          }
        }).catch((err: any) => {
          logger.error({ context: "project", error: err }, "Failed to check view cache");
        });
      } else {
        // Fallback if no redis
        projectService.incrementViewCount(project.id).catch((err: any) => {
          logger.error({ context: "project", id: project.id, error: err }, "Failed to increment view count");
        });
      }
    })
  );

  // PUT /projects/:id - Update project
  app.put(
    "/projects/:id",
    isAuthenticated,
    validateBody(insertProjectApiSchema.partial()),
    asyncHandler(async (req: Request, res: Response) => {
      const id = parseIntParam(res, req.params.id, "project ID");
            if (id === null) return;
      const project = await projectService.update(id, req.body);
      recordAudit("UPDATE", "project", id, null, req.body);
      res.json({
        success: true,
        message: "Project updated successfully",
        data: project
      });
    })
  );

  // DELETE /projects/:id - Delete project
  app.delete(
    "/projects/:id",
    isAuthenticated,
    asyncHandler(async (req: Request, res: Response) => {
      const id = parseIntParam(res, req.params.id, "project ID");
            if (id === null) return;
      await projectService.delete(id);
      recordAudit("DELETE", "project", id, null, null);
      res.status(204).send();
    })
  );
}

